export const scene: DialogueEntry[] = [
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "10:42。走廊。", background: Background.Chapter_10_Ch10_Act1_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "悠真房間的門剛帶上。", background: Background.Chapter_10_Ch10_Act1_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "門扣的聲音還黏在耳膜裡。", background: Background.Chapter_10_Ch10_Act1_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯走了。關了螢幕。帶上門。", background: Background.Chapter_10_Ch10_Act1_S0, portrait: Portrait.AsakuraMio_Exhausted },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯該去準備出門了。11:30。灣岸署。補筆錄。這些才是現在該想的事。", background: Background.Chapter_10_Ch10_Act1_S0, portrait: Portrait.AsakuraMio_Exhausted },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她站在走廊裡。", background: Background.Chapter_10_Ch10_Act1_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "沒有動。", background: Background.Chapter_10_Ch10_Act1_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "腳底貼著地板。像踩在膠水上。", background: Background.Chapter_10_Ch10_Act1_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯不行。", background: Background.Chapter_10_Ch10_Act1_S0, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯就這樣走掉。不回那句話。", background: Background.Chapter_10_Ch10_Act1_S0, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "螢幕上還掛著那句話。", background: Background.Chapter_10_Ch10_Act1_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "黑色海不是他一個人看見的。", background: Background.Chapter_10_Ch10_Act1_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯我截了圖。抄了紙。但我沒有回。對方不知道我是誰。不知道我是不是悠真。不知道我會不會再上線。", background: Background.Chapter_10_Ch10_Act1_S0, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯如果我現在走掉，關掉螢幕，出門去灣岸署，回來的時候那個帳號可能就不在了。", background: Background.Chapter_10_Ch10_Act1_S0, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯他說先別去筑波。他知道座標。", background: Background.Chapter_10_Ch10_Act1_S0, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯他知道有人在等這個帳號亮起來。這不是可以晾著的東西。", background: Background.Chapter_10_Ch10_Act1_S0, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她轉身。推開門。門扣又響了一聲。", background: Background.Chapter_10_Ch10_Act1_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "10:43。悠真的房間。螢幕是暗的。她剛才關掉了。", background: Background.Chapter_10_Ch10_Act1_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她坐回椅子上。", background: Background.Chapter_10_Ch10_Act1_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "膝蓋頂到桌底。", background: Background.Chapter_10_Ch10_Act1_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "和剛才一模一樣的位置。", background: Background.Chapter_10_Ch10_Act1_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她伸手按了電源。", background: Background.Chapter_10_Ch10_Act1_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "螢幕亮起來。", background: Background.Chapter_10_Ch10_Act1_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "遊戲介面載入。", background: Background.Chapter_10_Ch10_Act1_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "悠真的帳號頭像出現在右上角。", background: Background.Chapter_10_Ch10_Act1_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "旁邊的狀態欄——", background: Background.Chapter_10_Ch10_Act1_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "離線 8 日。", background: Background.Chapter_10_Ch10_Act1_S1 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯⋯⋯離線八日。剛才是上線中。", background: Background.Chapter_10_Ch10_Act1_S1, portrait: Portrait.AsakuraMio_Shocked },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯我關掉螢幕之後帳號又變回離線了。", background: Background.Chapter_10_Ch10_Act1_S1, portrait: Portrait.AsakuraMio_Shocked },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）不。不是變回。", background: Background.Chapter_10_Ch10_Act1_S1, portrait: Portrait.AsakuraMio_Shocked },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）是舊掌機的待機模式。關螢幕不等於登出。", background: Background.Chapter_10_Ch10_Act1_S1, portrait: Portrait.AsakuraMio_Shocked },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）但狀態顯示——", background: Background.Chapter_10_Ch10_Act1_S1, portrait: Portrait.AsakuraMio_Shocked },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她看著狀態欄。過了兩秒。數字跳了一下。", background: Background.Chapter_10_Ch10_Act1_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "離線 8 日 → 上線中。", background: Background.Chapter_10_Ch10_Act1_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "右下角同時跳出一個小提示。灰字。很小。", background: Background.Chapter_10_Ch10_Act1_S1 },
    { characterId: CharacterId.Message, character: "訊息", dialogue: "好友列表已更新", background: Background.Chapter_10_Ch10_Act1_S1 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯好友列表已更新。悠真的好友名單裡有人被加進去或移除過。系統在同步。", background: Background.Chapter_10_Ch10_Act1_S1, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯這也代表——帳號重新連線的時候，伺服器會通知好友列表裡所有人。", background: Background.Chapter_10_Ch10_Act1_S1, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯no_moon 不是神通廣大。他只是一直在等這個帳號重新亮起來。等了八天。", background: Background.Chapter_10_Ch10_Act1_S1, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她點開私訊介面。no_moon 的訊息還在那裡。五條。按時間排列。安靜地排著。", background: Background.Chapter_10_Ch10_Act1_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她看著那些訊息。", background: Background.Chapter_10_Ch10_Act1_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "暗號。", background: Background.Chapter_10_Ch10_Act1_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "你不是悠真。", background: Background.Chapter_10_Ch10_Act1_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "你是他姐姐嗎。", background: Background.Chapter_10_Ch10_Act1_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "黑色海不是他一個人看見的。", background: Background.Chapter_10_Ch10_Act1_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "想找他，先別去筑波。", background: Background.Chapter_10_Ch10_Act1_S1 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯五條。我沒有回過任何一條。", background: Background.Chapter_10_Ch10_Act1_S1, portrait: Portrait.AsakuraMio_Exhausted },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯他問我是不是他姐姐。他說黑色海不是他一個人看見的。他在等我回。", background: Background.Chapter_10_Ch10_Act1_S1, portrait: Portrait.AsakuraMio_Exhausted },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯回。不能回太多。不能回太快。", background: Background.Chapter_10_Ch10_Act1_S1, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯不能打悠真的全名——不對，對方已經知道帳號是悠真的。但不能打我的全名。", background: Background.Chapter_10_Ch10_Act1_S1, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯不。我已經決定了。要讓對方知道我是誰。否則他不會往下說。", background: Background.Chapter_10_Ch10_Act1_S1, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她的手指懸在鍵盤上方。一夜沒睡的手指。指節有點僵。她打了幾個字。刪掉。又打。又刪。", background: Background.Chapter_10_Ch10_Act1_S1 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯怎麼打。我是朝倉澪。悠真的姐姐。就這樣。不要多。不要解釋。", background: Background.Chapter_10_Ch10_Act1_S1, portrait: Portrait.AsakuraMio_Exhausted },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯不要說我查到了什麼。不要說座標。不要說夢話錄音。", background: Background.Chapter_10_Ch10_Act1_S1, portrait: Portrait.AsakuraMio_Exhausted },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯先讓對方知道我是誰。其他的等他確認我不是假的。", background: Background.Chapter_10_Ch10_Act1_S1, portrait: Portrait.AsakuraMio_Exhausted },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她深吸一口氣。打了下去。", background: Background.Chapter_10_Ch10_Act1_S1 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "我是朝倉澪。悠真的姐姐。", background: Background.Chapter_10_Ch10_Act1_S1, portrait: Portrait.AsakuraMio_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "發送。", background: Background.Chapter_10_Ch10_Act1_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "訊息出現在對話框裡。", background: Background.Chapter_10_Ch10_Act1_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "灰底白字。很短。", background: Background.Chapter_10_Ch10_Act1_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "像在門縫裡塞了一張紙條。", background: Background.Chapter_10_Ch10_Act1_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她等。十秒。二十秒。對方的頭像沒有亮。沒有「正在輸入」的提示。她盯著螢幕。眼睛乾澀。眨了一下。又眨了一下。", background: Background.Chapter_10_Ch10_Act1_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "三十秒。對方回了。", background: Background.Chapter_10_Ch10_Act1_S1 },
    { characterId: CharacterId.NoMoon, character: "no_moon", dialogue: "帳號可以被人用。訊息也可以。", background: Background.Chapter_10_Ch10_Act1_S1 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯⋯⋯", background: Background.Chapter_10_Ch10_Act1_S1, portrait: Portrait.AsakuraMio_Scared },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯他在懷疑我。不是不禮貌的懷疑。是那種被騙過太多次的懷疑。", background: Background.Chapter_10_Ch10_Act1_S1, portrait: Portrait.AsakuraMio_Scared },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯帳號可以被人用。訊息也可以。悠真的簡訊被代發過。他見過這種事。他見過帳號重新亮起來但坐在螢幕前面的不是本人。", background: Background.Chapter_10_Ch10_Act1_S1, portrait: Portrait.AsakuraMio_Scared },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯他不信任文字。不信任帳號。不信任「我是他姐姐」這五個字。", background: Background.Chapter_10_Ch10_Act1_S1, portrait: Portrait.AsakuraMio_Scared },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯他不是情報組織。情報組織不會這樣說話。", background: Background.Chapter_10_Ch10_Act1_S1, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯情報組織會直接查我的IP、查我的登入紀錄、查我的身分。他不查。", background: Background.Chapter_10_Ch10_Act1_S1, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯他只是告訴我：我不信你。像一個被偽造訊息嚇怕的普通人。", background: Background.Chapter_10_Ch10_Act1_S1, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她想了想。打了下去。", background: Background.Chapter_10_Ch10_Act1_S1 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "我不知道暗號。悠真沒跟我說過。", background: Background.Chapter_10_Ch10_Act1_S1, portrait: Portrait.AsakuraMio_Base },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "你要我怎麼證明？告訴我，我試試。", background: Background.Chapter_10_Ch10_Act1_S1, portrait: Portrait.AsakuraMio_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "發送。她看著自己的訊息。像在遞一張空白的紙過去。告訴對方：我什麼都沒有。但我在這裡。", background: Background.Chapter_10_Ch10_Act1_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "對方沉默了更久。一分鐘。螢幕上的游標閃著。她數著閃的次數。到第四十七下的時候，對方回了。", background: Background.Chapter_10_Ch10_Act1_S1 },
    { characterId: CharacterId.NoMoon, character: "no_moon", dialogue: "去看 bluefish_7。", background: Background.Chapter_10_Ch10_Act1_S1 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯bluefish_7。帳號名。不是暗號。不是組織名。看起來像普通遊戲帳號。藍色的魚。七。", background: Background.Chapter_10_Ch10_Act1_S1, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯他在給我一個可以自己查的東西。不是要我相信他。是讓我自己去看。", background: Background.Chapter_10_Ch10_Act1_S1, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "對方又發了兩行。", background: Background.Chapter_10_Ch10_Act1_S1 },
    { characterId: CharacterId.NoMoon, character: "no_moon", dialogue: "最後那張圖別下載。", background: Background.Chapter_10_Ch10_Act1_S1 },
    { characterId: CharacterId.NoMoon, character: "no_moon", dialogue: "看完晚點再說。", background: Background.Chapter_10_Ch10_Act1_S1 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯最後那張圖。別下載。和剛才一樣。不要留紀錄。看。手抄。然後離開。", background: Background.Chapter_10_Ch10_Act1_S1, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯他在教我怎麼不被追蹤。或者他在控制我能看到多少。我不知道是哪一個。", background: Background.Chapter_10_Ch10_Act1_S1, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯晚點再說。不是現在。他不想在網路上說太多。他不想在這個介面上留太多字。", background: Background.Chapter_10_Ch10_Act1_S1, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯他給了我一個方向。然後要我自己走過去。", background: Background.Chapter_10_Ch10_Act1_S1, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她剛想打字問 bluefish_7 是誰。手指剛碰到鍵盤。", background: Background.Chapter_10_Ch10_Act1_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "手機震了。", background: Background.Chapter_10_Ch10_Act1_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "不是遊戲。是行事曆。提醒還掛在螢幕頂部。", background: Background.Chapter_10_Ch10_Act1_S1 },
    { characterId: CharacterId.Message, character: "訊息", dialogue: "11:30　灣岸署補筆錄　請攜帶身分證件　保持手機開機", background: Background.Chapter_10_Ch10_Act1_S1 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯十一點半。提醒。我設了兩條。一條提前一小時。一條提前四十五分鐘。都響過了。我沒有注意到。現在是——", background: Background.Chapter_10_Ch10_Act1_S1, portrait: Portrait.AsakuraMio_Exhausted },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她看了一眼手機上的時間。", background: Background.Chapter_10_Ch10_Act1_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "10:51。", background: Background.Chapter_10_Ch10_Act1_S1 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯十點五十一。", background: Background.Chapter_10_Ch10_Act1_S1, portrait: Portrait.AsakuraMio_Exhausted },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）從這裡到灣岸署，電車加走路，還要寄放東西。", background: Background.Chapter_10_Ch10_Act1_S1, portrait: Portrait.AsakuraMio_Exhausted },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）不夠。", background: Background.Chapter_10_Ch10_Act1_S1, portrait: Portrait.AsakuraMio_Exhausted },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）時間不夠了。我不能在這裡繼續聊。", background: Background.Chapter_10_Ch10_Act1_S1, portrait: Portrait.AsakuraMio_Exhausted },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯截圖。手抄。bluefish_7。先記下來。晚點查。現在必須走。", background: Background.Chapter_10_Ch10_Act1_S1, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她按了截圖。", background: Background.Chapter_10_Ch10_Act1_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "螢幕閃了一下。", background: Background.Chapter_10_Ch10_Act1_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "no_moon 的三條新訊息連同帳號名一起存進手機相簿。", background: Background.Chapter_10_Ch10_Act1_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "然後她摸出那張紙。", background: Background.Chapter_10_Ch10_Act1_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "攤開。", background: Background.Chapter_10_Ch10_Act1_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "找到最後一條空白。", background: Background.Chapter_10_Ch10_Act1_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "壓著筆寫。", background: Background.Chapter_10_Ch10_Act1_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "bluefish_7。最後一張。不要下載。晚點再說。", background: Background.Chapter_10_Ch10_Act1_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她寫得很快。字比剛才更歪。一夜沒睡的手在抖。筆尖刮過紙面。bluefish 的 f 拖了一道墨槓。她沒有重寫。", background: Background.Chapter_10_Ch10_Act1_S1 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯bluefish_7。記下了。不能現在查。不能現在打開那個帳號。要出門了。要面對警察了。", background: Background.Chapter_10_Ch10_Act1_S1, portrait: Portrait.AsakuraMio_Exhausted },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她把紙摺起來。", background: Background.Chapter_10_Ch10_Act1_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "塞進內袋。", background: Background.Chapter_10_Ch10_Act1_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "和之前抄的那一頁疊在一起。", background: Background.Chapter_10_Ch10_Act1_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "整張紙已經快寫滿了。", background: Background.Chapter_10_Ch10_Act1_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "座標。檔名。帳號。訊息。", background: Background.Chapter_10_Ch10_Act1_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "現在又多了 bluefish_7。", background: Background.Chapter_10_Ch10_Act1_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她看著螢幕。no_moon 沒有再發訊息。對話停在那裡。看完晚點再說。", background: Background.Chapter_10_Ch10_Act1_S1 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯晚點。他說晚點。他不怕我消失。", background: Background.Chapter_10_Ch10_Act1_S1, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯因為他知道——如果我真的在找悠真，我會回來。如果我不回來，那就代表我不是真的。", background: Background.Chapter_10_Ch10_Act1_S1, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她把悠真的舊掌機從桌面上拿起來。", background: Background.Chapter_10_Ch10_Act1_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "比手機大一點。比筆電小。", background: Background.Chapter_10_Ch10_Act1_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "悠真用它登入遊戲帳號。", background: Background.Chapter_10_Ch10_Act1_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她不能把它留在這裡。", background: Background.Chapter_10_Ch10_Act1_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "也不能把它帶進灣岸署。", background: Background.Chapter_10_Ch10_Act1_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "但她現在沒有時間想這個。", background: Background.Chapter_10_Ch10_Act1_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她把掌機塞進背包側袋。拉上拉鍊。", background: Background.Chapter_10_Ch10_Act1_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她關掉螢幕。", background: Background.Chapter_10_Ch10_Act1_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "房間暗下來。", background: Background.Chapter_10_Ch10_Act1_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "窗簽縫裡的上午光。", background: Background.Chapter_10_Ch10_Act1_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "灰的。", background: Background.Chapter_10_Ch10_Act1_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "比剛才亮了一點。但還是灰的。", background: Background.Chapter_10_Ch10_Act1_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "10:52。", background: Background.Chapter_10_Ch10_Act1_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她站起來。", background: Background.Chapter_10_Ch10_Act1_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "椅子往後滑了一聲。", background: Background.Chapter_10_Ch10_Act1_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她沒有回頭看悠真的房間。", background: Background.Chapter_10_Ch10_Act1_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她帶上門。", background: Background.Chapter_10_Ch10_Act1_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "門扣響了一聲。", background: Background.Chapter_10_Ch10_Act1_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "這次她沒有停。", background: Background.Chapter_10_Ch10_Act1_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "走廊。她的房間在隔壁。她需要整理東西。兩本筆記。一個決定。然後出門。", background: Background.Chapter_10_Ch10_Act1_S1 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯bluefish_7。藍色的魚。七。另一個孩子。另一個沒有回來的人。", background: Background.Chapter_10_Ch10_Act1_S1, portrait: Portrait.AsakuraMio_Exhausted },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯晚點。先活過灣岸署再說。", background: Background.Chapter_10_Ch10_Act1_S1, portrait: Portrait.AsakuraMio_Exhausted },
];
